\":\"Pruva Meyhane Kalkan | Kalkan Rakı Balık, Meyhane ve Fasıl Eğlencesi\",\"en\":\"Pruva Meyhane Kalkan | Kalkan Rakı Balık, Meyhane ve Fasıl Eğlencesi\"}','text','general',NULL,'2026-03-16 17:19:14'),(16,'address','{\"tr\":\"Kalkan, İskele Sk. No:13, 07960 Kaş/Antalya\",\"en\":\"Kalkan, İskele Sk. No:13, 07960 Kaş/Antalya\"}','text','social',NULL,'2026-03-16 18:35:15'),(17,'phone','{\"tr\":\"+90 535 458 55 44\",\"en\":\"+90 535 458 55 44\"}','text','social',NULL,'2026-03-16 18:35:15'),(18,'whatsapp','{\"tr\":\"+90 535 458 55 44\",\"en\":\"+90 535 458 55 44\"}','text','social',NULL,'2026-03-16 18:35:15'),(19,'email','{\"tr\":\"info@pruvakalkan.com\",\"en\":\"info@pruvakalkan.com\"}','text','social',NULL,'2026-03-16 18:35:15'),(20,'logo','{\"tr\":\"settings/01KKW5EKJ6TY1ZVRZRYMFC7DY1.png\",\"en\":\"settings/01KKW5EKJ6TY1ZVRZRYMFC7DY1.png\"}','image','branding',NULL,'2026-03-16 17:29:57'),(21,'hero_images','{\"tr\":[],\"en\":[]}','images','branding','2026-03-16 15:56:29','2026-03-16 18:40:40'),(22,'story_image','{\"tr\":\"settings/He8ISZaMk2dNto5y6EjnjcNFhV8PA321kpOurfXw.webp\",\"en\":\"settings/He8ISZaMk2dNto5y6EjnjcNFhV8PA321kpOurfXw.webp\"}','image','branding','2026-03-16 15:56:29','2026-03-16 17:56:16'),(23,'menu_restaurant_image','{\"en\":null}','image','branding','2026-03-16 15:56:29','2026-03-16 18:39:46'),(24,'menu_snacks_image','{\"en\":null}','image','branding','2026-03-16 15:56:29','2026-03-16 18:39:46'),(25,'menu_drinks_image','{\"en\":null}','image','branding','2026-03-16 15:56:29','2026-03-16 18:39:46'),(26,'parallax_image','{\"tr\":\"settings/curSuxxc0HPJwgoioCILxllB3gm3ECyhG4qfi7Yn.webp\",\"en\":\"settings/curSuxxc0HPJwgoioCILxllB3gm3ECyhG4qfi7Yn.webp\"}','image','branding','2026-03-16 15:56:29','2026-03-16 17:58:10'),(27,'hero_welcome_text','{\"tr\":\"Pruva\'ya Hoş Geldiniz\",\"en\":\"Welcome to Pruva\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(28,'hero_title','{\"tr\":\"Denize Sıfır,<br><span class=\\\"font-normal italic\\\">Lezzet, Manzara ve Keyfin Buluşma Noktası</span>\",\"en\":\"Right on the Seafront,<br><span class=\\\"font-normal italic\\\">The Meeting Point of Taste, View and Enjoyment</span>\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 18:15:40'),(29,'hero_discover_menu_text','{\"tr\":\"Menüyü Keşfet\",\"en\":\"Discover Menu\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(30,'hero_book_table_text','{\"tr\":\"Rezervasyon Yap\",\"en\":\"Book a Table\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(31,'about_welcome_text','{\"tr\":\"Hikayemiz\",\"en\":\"Our Story\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(32,'about_title','{\"tr\":\"Denize sıfır,<br><span class=\\\"italic text-brand-accent\\\">lezzetle ve keyifle iç içe bir meyhane deneyimi…</span>\",\"en\":\"A flavor experience<br><span class=\\\"italic text-brand-accent\\\">away from the city\'s crowd</span>\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 18:12:04'),(33,'about_description_1','{\"tr\":\"Pruva Meyhane, Kalkan Limanı’nda denize sıfır konumuyla; taze deniz ürünleri, özenle hazırlanan mezeler ve Akdeniz ruhunu taşıyan özel tatları aynı sofrada buluşturan özel bir lezzet durağıdır.  Burada her masa, denizin hemen kıyısında kurulan uzun sohbetlere, gün batımına karşı kaldırılan kadehlere ve unutulmaz akşamlara eşlik eder. Pruva’da misafirlerimize yalnızca bir yemek değil; manzara, lezzet ve atmosferin kusursuz şekilde buluştuğu ayrıcalıklı bir meyhane deneyimi sunuyoruz.\",\"en\":\"Pruva Meyhane, located right on the seafront in Kalkan Harbor, is a special culinary destination that brings together fresh seafood, carefully prepared mezes, and unique flavors embodying the spirit of the Mediterranean.  Here, every table is set right by the sea, perfect for long conversations, toasts raised against the sunset, and unforgettable evenings. At Pruva, we offer our guests not just a meal, but a privileged meyhane (traditional Turkish tavern) experience where view, flavor, and atmosphere perfectly complement each other.\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 18:13:40'),(34,'about_description_2','{\"tr\":\"Misafirlerine, gurme yemekleri eğlence ve nefes kesen gün batımı deniz manzarasıyla birleştiren canlı bir deneyim sunuyoruz.\",\"en\":\"Offering guests a vibrant experience that combines gourmet dining with entertainment and breathtaking sunset sea views.\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(35,'about_button_text','{\"tr\":\"Hikayemizi Oku\",\"en\":\"Read Our Story\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(36,'experience_title','{\"tr\":\"Fasıl Eğlenceleri\",\"en\":\"Turkish Traditional Music Entertainment\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 17:59:13'),(37,'experience_subtitle','{\"tr\":\"Klasik Fasıl ile Gerçek Meyhane \",\"en\":\" Classical Turkish Music and an Authentic Tavern\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 18:00:01'),(38,'culinary_welcome_text','{\"tr\":\"Mutfak Mükemmelliği\",\"en\":\"Culinary Excellence\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(39,'culinary_title','{\"tr\":\"Duyular İçin İşlendi\",\"en\":\"Crafted for the Senses\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(40,'culinary_button_text','{\"tr\":\"Tüm Menüyü Görüntüle\",\"en\":\"View Full Menu\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(41,'testimonials_welcome_text','{\"tr\":\"Referanslar\",\"en\":\"Testimonials\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(42,'testimonials_title','{\"tr\":\"Misafirlerimiz Ne Diyor\",\"en\":\"What Our Guests Say\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(43,'testimonials_footer_text','{\"tr\":\"Bizi ziyaret ettiniz mi?\",\"en\":\"Have you visited us?\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(44,'testimonials_google_button','{\"tr\":\"Google\'da Değerlendir\",\"en\":\"Review on Google\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(45,'testimonials_tripadvisor_button','{\"tr\":\"TripAdvisor\'da Değerlendir\",\"en\":\"Review on TripAdvisor\"}','text','homepage','2026-03-16 15:56:29','2026-03-16 15:56:29'),(46,'our_story_meta_title','{\"tr\":\"Bir Akdeniz Masalı: Pruva\'nın Hikayesi | Pruva Restaurant Kaş\",\"en\":\"A Mediterranean Tale: The Pruva Story | Pruva Restaurant Kaş\"}','text','seo','2026-03-16 17:23:13','2026-03-16 18:24:02'),(47,'our_story_meta_description','{\"tr\":\"Denizin, toprağın ve ateşin kalbinden gelen bir lezzet yolculuğu.\",\"en\":\"A journey of flavor from the heart of the sea, the land, and the flame.\"}','text','seo','2026-03-16 17:23:13','2026-03-16 18:24:02'),(48,'gallery_meta_title','{\"tr\":\"Galeri | Pruva Meyhane Kalkan\",\"en\":\"Gallery | Pruva Tavern Kalkan\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:26:40'),(49,'gallery_meta_description','{\"tr\":\"Pruva Restaurant\'tan kareler, lezzetler ve manzara.\",\"en\":\"Snapshots, flavors, and views from Pruva Restaurant.\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:23:13'),(50,'contact_meta_title','{\"tr\":\"İletişim | Pruva Meyhane Kalkan\",\"en\":\"Contact | Pruva Tavern Kalkan\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:27:12'),(51,'contact_meta_description','{\"tr\":\"Bizimle iletişime geçin, rezervasyon yapın.\",\"en\":\"Get in touch with us, make a reservation.\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:23:13'),(52,'menu_meta_title','{\"tr\":\"Menü | Pruva Restaurant Kaş\",\"en\":\"Menu | Pruva Restaurant Kaş\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:23:13'),(53,'menu_meta_description','{\"tr\":\"Akdeniz mutfağının en seçkin lezzetleri, taze deniz ürünleri ve mezeler.\",\"en\":\"The most exclusive flavors of Mediterranean cuisine, fresh seafood and appetizers.\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:23:13'),(54,'blog_meta_title','{\"tr\":\"Günlük & Hikayeler | Pruva Restaurant Kaş\",\"en\":\"Journal & Stories | Pruva Restaurant Kaş\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:23:13'),(55,'blog_meta_description','{\"tr\":\"Akdeniz\'in kalbinden en son haberleri, yemek tariflerini ve hikayeleri keşfedin.\",\"en\":\"Discover the latest news, recipes, and stories from the heart of the Mediterranean.\"}','text','seo','2026-03-16 17:23:13','2026-03-16 17:23:13'),(56,'our_story_hero_image','{\"en\":null}','image','our_story','2026-03-16 18:23:46','2026-03-16 18:39:46'),(57,'our_story_hero_title','{\"tr\":\"Bir Akdeniz Masalı: Pruva\'nın Hikayesi\",\"en\":\"A Mediterranean Tale: The Pruva Story\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(58,'our_story_hero_subtitle','{\"tr\":\"Denizin, toprağın ve ateşin kalbinden gelen bir lezzet yolculuğu.\",\"en\":\"A journey of flavor from the heart of the sea, the land, and the flame.\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(59,'our_story_roots_title','{\"tr\":\"Köklerimiz\",\"en\":\"Our Roots\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(60,'our_story_roots_content','{\"tr\":\"Pruva\'nın hikayesi, antik zamanlardan beri medeniyetlerin beşiği olmuş, Akdeniz\'in en kristal kıyılarına sahip Kaş\'ın ruhunda başlar. \'Pruva\' ismini, bu toprakların en kadim sakini olan ve bilgeliği, barışı ve bereketi simgeleyen zeytin ağacından alır. Yüzyıllardır bu coğrafyada kök salan zeytin ağaçları gibi, biz de yerel kültürümüzün ve misafirperverliğimizin derinliklerine kök saldık. Her bir yaprağında gümüş parıltılar taşıyan zeytin dalları, mutfağımızın ve soframızın temelini oluşturur. Pruva, sadece bir restoran değil, bu bölgenin sunduğu tüm bereketi onurlandırmak için kurulmuş bir buluşma noktasıdır.\",\"en\":\"The story of Pruva begins in the spirit of Kaş, home to the most crystalline shores of the Mediterranean and a cradle of civilizations since ancient times. Pruva takes its name from the oldest inhabitant of this land: the olive tree, symbolizing wisdom, peace, and abundance. Just as the olive trees have taken root here for centuries, we have rooted ourselves in the depths of our local culture and hospitality. Olive branches, with silver glimmers on every leaf, form the foundation of our kitchen and our table. Pruva is not just a restaurant; it is a gathering point established to honor all the bounty this region offers.\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(61,'our_story_roots_image','{\"en\":null}','image','our_story','2026-03-16 18:23:46','2026-03-16 18:39:46'),(62,'our_story_sea_title','{\"tr\":\"Denizin Bereketi\",\"en\":\"Bounty of the Sea\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(63,'our_story_sea_content','{\"tr\":\"Göz alabildiğine uzanan turkuaz sular, Pruva mutfağının her gün tazelenen ilham kaynağıdır. Çukurbağ Yarımadası\'nın kıyılarından soframıza uzanan bu yolculukta, sadece en taze malzemeleri seçiyoruz. Sabahın ilk ışıklarıyla ağlarını çeken yerel balıkçıların bereketi, ızgaralarımızda ve mezelerimizde hayat bulur. Levrekten çipuraya, kalamardan ahtapota kadar her deniz ürünü, denizin o kendine has tuzlu kokusunu ve tazeliğini koruyacak şekilde özenle hazırlanır. Bizim için her tabak, Akdeniz’in cömertliğini anlatan bir sahnedir.\",\"en\":\"Turquoise waters, stretching as far as the eye can see, are the inspiration for the Pruva kitchen that is refreshed every day. In this journey from the shores of the Çukurbağ Peninsula to our table, we choose only the freshest ingredients. The bounty of local fishermen pulling their nets with the first light of morning comes to life in our grills and mezzes. From seabass to seabream, calamari to octopus, every seafood item is carefully prepared to preserve that unique salty scent and freshness of the sea. For us, every plate is a stage telling the story of Mediterranean generosity.\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(64,'our_story_sea_image','{\"en\":null}','image','our_story','2026-03-16 18:23:46','2026-03-16 18:39:46'),(65,'our_story_flame_title','{\"tr\":\"Ateşin Dansı\",\"en\":\"Dance of the Flame\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(66,'our_story_flame_content','{\"tr\":\"Mutfağımızın merkezinde, lezzetlerin mühürlendiği ve geleneksel dokunuşların modern tekniklerle buluştuğu odun ateşimiz yanar. Bir \'Modern Meyhane\' konseptiyle, geçmişin o samimi atmosferini günümüzün estetik anlayışıyla harmanladık. Etlerimizin ve mevsim sebzelerinin kömür ateşindeki o isli kokusu, Pruva deneyiminin ayrılmaz bir parçasıdır. Geleneksel Anadolu reçetelerini, Akdeniz\'in hafifliği ve ferahlığıyla yeniden yorumlayarak, misafirlerimize hem tanıdık hem de şaşırtıcı lezzet kombinasyonları sunuyoruz. Her lokma, emeğin ve tutkunun bir yansımasıdır.\",\"en\":\"At the center of our kitchen burns the wood fire where flavors are sealed and traditional touches meet modern techniques. With a \'Modern Meyhane\' concept, we have blended that intimate atmosphere of the past with today\'s aesthetic understanding. That smoky scent of our meats and seasonal vegetables on the charcoal fire is an inseparable part of the Pruva experience. By reinterpreting traditional Anatolian recipes with the lightness and freshness of the Mediterranean, we offer our guests flavor combinations that are both familiar and surprising. Every bite is a reflection of labor and passion.\"}','text','our_story','2026-03-16 18:23:46','2026-03-16 18:23:46'),(67,'our_story_flame_image','{\"en\":null}','image','our_story','2026-03-16 18:23:46','2026-03-16 18:39:46'),(68,'our_story_gathering_title','{\"tr\":\"Sofranın Ruhu\",\"en\":\"The Soul of the Table\"}','text','our_story','2026-03-16 18:23:47','2026-03-16 18:23:47'),(69,'our_story_gathering_content','{\"tr\":\"Kaş\'ın büyüleyici gün batımı eşliğinde kurulan sofralar, bizim için paylaşmanın ve dostluğun en saf halidir. Çukurbağ Yarımadası\'nın o eşsiz manzarasına karşı, rüzgarın taşıdığı zeytin kokuları arasında kadehlerin dostluğa kalktığı her an kıymetlidir. Pruva\'da sadece yemek servis etmiyoruz; aynı zamanda unutulmaz anılar inşa ediyoruz. Güler yüzlü ekibimiz, her misafirimizin kendini evinde hissetmesini sağlamak için büyük bir tutkuyla çalışır. Müziğin yumuşak ritmi, dalgaların sesi ve sevdiklerinizle paylaştığınız o eşsiz sohbetler, Pruva\'yı Kaş\'ın kalbinde özel bir kaçış noktası yapar.\",\"en\":\"Tables set accompanied by the mesmerizing sunset of Kaş are, for us, the purest form of sharing and friendship. Set against that unique view of the Çukurbağ Peninsula, among the scents of olives carried by the wind, every moment when glasses are raised to friendship is precious. At Pruva, we don\'t just serve food; we also build unforgettable memories. Our smiling team works with great passion to ensure every guest feels at home. The soft rhythm of music, the sound of waves, and those unique conversations shared with loved ones make Pruva a special escape point in the heart of Kaş.\"}','text','our_story','2026-03-16 18:23:47','2026-03-16 18:23:47'),(70,'our_story_gathering_image','{\"en\":null}','image','our_story','2026-03-16 18:23:47','2026-03-16 18:39:46'),(71,'our_story_conclusion_title','{\"tr\":\"Geleceğe Miras\",\"en\":\"Legacy for the Future\"}','text','our_story','2026-03-16 18:23:47','2026-03-16 18:23:47'),(72,'our_story_conclusion_content','{\"tr\":\"Pruva, her geçen gün büyüyen ve gelişen bir aile; ancak özündeki saflığı ve yerelliği asla kaybetmeyecek bir sözdür. Bizler, bu toprakların hikayesini tabaklarımızda anlatmaya, her gün aynı heyecanla mutfağımıza girmeye ve Akdeniz\'in ruhunu her bir misafirimize hissettirmeye devam edeceğiz. Bu hikayenin bir parçası olduğunuz için teşekkür ederiz. Sizi, bu kıyı masalının yeni sayfalarını birlikte yazmaya, zeytin ağaçlarının gölgesinde bir lezzet şölenine davet ediyoruz.\",\"en\":\"Pruva is a family growing and developing every day; but it is a promise that will never lose its purity and locality at its core. We will continue to tell the story of this land on our plates, to enter our kitchen with the same excitement every day, and to make every guest feel the spirit of the Mediterranean. Thank you for being a part of this story. We invite you to a feast of flavor in the shadow of the olive trees, to write the new pages of this coastal tale together.\"}','text','our_story','2026-03-16 18:23:47','2026-03-16 18:23:47'),(73,'our_story_discover_menu_text','{\"tr\":\"Menüyü Keşfet\",\"en\":\"Discover Menu\"}','text','our_story','2026-03-16 18:23:47','2026-03-16 18:23:47'),(74,'facebook_url','{\"en\":\"https://www.facebook.com/pruvakalkan\",\"tr\":\"https://www.facebook.com/pruvakalkan\"}','text','social','2026-03-16 18:32:15','2026-03-16 18:42:48'),(75,'instagram_url','{\"en\":\"http://instagram.com/pruvakalkan/\",\"tr\":\"http://instagram.com/pruvakalkan/\"}','text','social','2026-03-16 18:32:15','2026-03-16 18:42:48'),(76,'google_reviews_url','{\"en\":\"https://maps.app.goo.gl/YfQdSMGERuMR4b8H6\",\"tr\":\"https://maps.app.goo.gl/YfQdSMGERuMR4b8H6\"}','text','social','2026-03-16 18:32:15','2026-03-16 18:42:48'),(77,'tripadvisor_reviews_url','{\"en\":null}','text','social','2026-03-16 18:32:15','2026-03-16 18:42:48'),(78,'footer_text','{\"tr\":\"Kalkan Limanı’nın eşsiz atmosferinde, taze deniz ürünleri, özenli mezeler ve hafızada kalan bir meyhane deneyimi.\",\"en\":\"Located right on Kalkan Harbour, offering fresh seafood, refined mezes, and an unforgettable tavern atmosphere.\"}','text','branding','2026-03-16 18:35:15','2026-03-16 18:40:40');
